 1	import { DetailsItem } from "copiedFromConsole/utils/details-item";
 2	import { LabelList } from "copiedFromConsole/utils/label-list";
 3	import OwnerReferences from "copiedFromConsole/utils/OwnerReferences";
 4	import { Selector } from "copiedFromConsole/utils/selector";
 5	import { ModalId } from "components/modals/Modals";
 6	import { useModals } from "components/modals/ModalsContext";
 7	import { NodeHealthCheck } from "data/types";
 8	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 9	import * as React from "react";
10	import { Timestamp } from "@openshift-console/dynamic-plugin-sdk";
11	import { size, get } from "lodash-es";
12	import { DescriptionList } from "@patternfly/react-core";
13	import { nodeHealthCheckStringKind } from "../../../data/model";
14	
15	export type ResourceSummaryProps = {
16	  resource: NodeHealthCheck;
17	  canEdit: boolean;
18	};
19	
20	export const DetailsLeftPane: React.FC<ResourceSummaryProps> = ({
21	  resource,
22	  canEdit,
23	}) => {
24	  const { t } = useNodeHealthCheckTranslation();
25	  const { metadata } = resource;
26	  const modalsContext = useModals();
27	  return (
28	    <DescriptionList aria-label={t("NodeHealthCheck details")}>
29	      <DetailsItem label={t("Name")} obj={resource} path={"metadata.name"} />
30	      <DetailsItem
31	        label={t("Labels")}
32	        obj={resource}
33	        path="metadata.labels"
34	        valueClassName="details-item__value--labels"
35	        canEdit={canEdit}
36	        editAsGroup
37	        onEdit={() => modalsContext.openModal(ModalId.EDIT_LABELS, resource)}
38	      >
39	        <LabelList kind={nodeHealthCheckStringKind} labels={metadata.labels} />
40	      </DetailsItem>
41	      <DetailsItem
42	        label={t("Annotations")}
43	        obj={resource}
44	        path="metadata.annotations"
45	        onEdit={() =>
46	          modalsContext.openModal(ModalId.EDIT_ANNOTATIONS, resource)
47	        }
48	      >
49	        {t("{{count}} annotation", {
50	          count: size(metadata.annotations),
51	        })}
52	      </DetailsItem>
53	      <DetailsItem
54	        label={t("Node selector")}
55	        obj={resource}
56	        path={"spec.selector"}
57	      >
58	        <Selector kind={t("Node")} selector={get(resource, "spec.selector")} />
59	      </DetailsItem>
60	      <DetailsItem
61	        label={t("Created at")}
62	        obj={resource}
63	        path="metadata.creationTimestamp"
64	      >
65	        <Timestamp timestamp={metadata.creationTimestamp} />
66	      </DetailsItem>
67	      <DetailsItem
68	        label={t("Owner")}
69	        obj={resource}
70	        path="metadata.ownerReferences"
71	      >
72	        <OwnerReferences obj={resource} />
73	      </DetailsItem>
74	    </DescriptionList>
75	  );
76	};

